<?php get_header(); ?><div class="cdb-container"><?php cdb_output_breadcrumbs(); ?><header><h1><?php single_cat_title(); ?></h1><?php if(1===max(1,get_query_var('paged'))){$d=category_description(); if($d){echo '<div class="archive-description">'.wp_kses_post($d).'</div>';}} ?></header><div class="post-grid"><?php if(have_posts()): while(have_posts()):the_post(); get_template_part('template-parts/content-card'); endwhile; else:?><p>Nenhum conteúdo encontrado.</p><?php endif;?></div><?php get_template_part('template-parts/pagination'); ?></div><?php get_footer(); ?>
